"use strict";angular.module("lucaskatayama.angular-wistiauploader",[]).directive("lkWistiauploader",["$log","$compile","$parse",function($log,$compile,$parse){return{restrict:"E",scope:{},replace:!0,transclusion:!1,compile:function(element,attrs){var html="<div class='wistia-uploader'><span class='btn btn-success fileinput-button'>Choose File<input type='file' name='file' /></span><div id='progress' class='progress'><div class='bar progress-bar progress-bar-success'></div></div></div>",newElem=$(html);return element.replaceWith(newElem),function(scope,element,attrs,controller){var el=$(element);el.fileupload({url:"https://upload.wistia.com?api_password="+attrs.token,progressall:function(e,data){var progress=parseInt(data.loaded/data.total*100,10);el.find("#progress .bar").css("width",progress+"%")},done:function(e,data){var result=data.result,id=result.hashed_id,html='<script src="//fast.wistia.com/embed/medias/'+id+'.jsonp" async></script><script src="//fast.wistia.com/assets/external/E-v1.js" async></script><div class="wistia_responsive_padding" style="padding:42.5% 0 0 0;position:relative;"><div class="wistia_responsive_wrapper" style="height:100%;left:0;position:absolute;top:0;width:100%;"><div class="wistia_embed wistia_async_'+id+' videoFoam=true autoPlay=true" style="height:100%;width:100%">&nbsp;</div></div></div>',video=$(html);el.html(video)},error:function(e,data){el.html(e.responseJSON.error)}})}},template:function(element,attrs){var defaultsAttrs={};for(var xx in defaultsAttrs)void 0===attrs[xx]&&(attrs[xx]=defaultsAttrs[xx]);var html="<div class='fileupload'>";return html+="</div>"},controller:function($scope,$element,$attrs){}}}]);